import json,collections
sums=collections.defaultdict(float); n=0; keys=set()
for line in open('criteria.jsonl'):
    line=line.strip()
    if not line: continue
    o=json.loads(line)
    # find dimension weights structure
    def walk(d,path=''):
        yield path,d
        if isinstance(d,dict):
            for k,v in d.items(): yield from walk(v,path+'/'+str(k))
        elif isinstance(d,list):
            for i,v in enumerate(d): yield from walk(v,path+'/'+str(i))
    # try common shapes
    n+=1
    if n==1:
        print("TOPKEYS", list(o.keys()))
        print(json.dumps(o,ensure_ascii=False)[:1500])
    break
